import{_ as d,H as e,f as o,i as a}from"./chunks/framework.eFU6Tutu.js";const g=JSON.parse('{"title":"内部原理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/how-it-works.md","filePath":"guide/how-it-works.md"}'),n={name:"guide/how-it-works.md"};function r(c,t,s,i,p,l){return e(),o("div",null,[...t[0]||(t[0]=[a(`<h1 id="内部原理" tabindex="-1">内部原理 <a class="header-anchor" href="#内部原理" aria-label="Permalink to &quot;内部原理&quot;">​</a></h1><p>invnz 的转换过程可以分为三个步骤。本文详细讲解每一步的内部机制。</p><h2 id="第一步-拆解音素" tabindex="-1">第一步：拆解音素 <a class="header-anchor" href="#第一步-拆解音素" aria-label="Permalink to &quot;第一步：拆解音素&quot;">​</a></h2><p>拼音由声母和韵母组成。invnz 把韵母进一步拆分为<strong>音素（phoneme）</strong>——最小的发音单位。</p><h3 id="韵母分解表" tabindex="-1">韵母分解表 <a class="header-anchor" href="#韵母分解表" aria-label="Permalink to &quot;韵母分解表&quot;">​</a></h3><p>以下韵母会被拆分为多个音素（不在表中的保持原样）：</p><table tabindex="0"><thead><tr><th>韵母</th><th>分解</th><th>示例拼音</th><th>音素序列</th></tr></thead><tbody><tr><td>ia</td><td>i_a</td><td>lia</td><td><code>l</code> + <code>i</code> + <code>a</code></td></tr><tr><td>iao</td><td>i_ao</td><td>biao</td><td><code>b</code> + <code>i</code> + <code>ao</code></td></tr><tr><td>iu</td><td>i_ou</td><td>liu</td><td><code>l</code> + <code>i</code> + <code>ou</code></td></tr><tr><td>ian</td><td>ie_an</td><td>bian</td><td><code>b</code> + <code>ie</code> + <code>an</code></td></tr><tr><td>in</td><td>i_en</td><td>bin</td><td><code>b</code> + <code>i</code> + <code>en</code></td></tr><tr><td>iang</td><td>i_ang</td><td>liang</td><td><code>l</code> + <code>i</code> + <code>ang</code></td></tr><tr><td>ing</td><td>i_eng</td><td>ling</td><td><code>l</code> + <code>i</code> + <code>eng</code></td></tr><tr><td>ua</td><td>u_a</td><td>gua</td><td><code>g</code> + <code>u</code> + <code>a</code></td></tr><tr><td>uai</td><td>u_ai</td><td>guai</td><td><code>g</code> + <code>u</code> + <code>ai</code></td></tr><tr><td>ui</td><td>u_ei</td><td>gui</td><td><code>g</code> + <code>u</code> + <code>ei</code></td></tr><tr><td>uan</td><td>u_an</td><td>guan</td><td><code>g</code> + <code>u</code> + <code>an</code></td></tr><tr><td>un</td><td>u_en</td><td>gun</td><td><code>g</code> + <code>u</code> + <code>en</code></td></tr><tr><td>uang</td><td>u_ang</td><td>guang</td><td><code>g</code> + <code>u</code> + <code>ang</code></td></tr><tr><td>ong</td><td>ong</td><td>hong</td><td><code>h</code> + <code>ong</code>（整体）</td></tr><tr><td>iong</td><td>iong</td><td>xiong</td><td><code>x</code> + <code>iong</code>（整体）</td></tr><tr><td>üe</td><td>ve</td><td>nüe</td><td><code>n</code> + <code>ve</code></td></tr><tr><td>üan</td><td>ve_an</td><td>quan</td><td><code>q</code> + <code>ve</code> + <code>an</code></td></tr><tr><td>ün</td><td>v_en</td><td>qun</td><td><code>q</code> + <code>v</code> + <code>en</code></td></tr></tbody></table><h3 id="特殊规则" tabindex="-1">特殊规则 <a class="header-anchor" href="#特殊规则" aria-label="Permalink to &quot;特殊规则&quot;">​</a></h3><p><strong>i 省略</strong>：当声母为 <code>j</code> <code>q</code> <code>x</code> <code>zh</code> <code>ch</code> <code>sh</code> <code>r</code> <code>z</code> <code>c</code> <code>s</code> 时，韵母中独立的 <code>i</code> 被省略：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ji     → j_i     → j_i    （纯韵母，不变）</span></span>
<span class="line"><span>jin    → j_i_en  → j_en   （i 被省略）</span></span>
<span class="line"><span>jing   → j_i_eng → j_eng  （i 被省略）</span></span>
<span class="line"><span>xin    → x_i_en  → x_en   （i 被省略）</span></span></code></pre></div><p>但 <code>iong</code> 是整体音素，不触发 i 省略：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>xiong  → x_iong  → x_iong （iong 整体，不变）</span></span></code></pre></div><p><strong>bpmf + o → uo</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bo  → b_uo</span></span>
<span class="line"><span>po  → p_uo</span></span>
<span class="line"><span>mo  → m_uo</span></span>
<span class="line"><span>fo  → f_uo</span></span></code></pre></div><p><strong>jqx + u → ü</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ju   → j_v</span></span>
<span class="line"><span>qu   → q_v</span></span>
<span class="line"><span>xu   → x_v</span></span>
<span class="line"><span>juan → j_ve_an</span></span></code></pre></div><h2 id="第二步-音素-→-字根" tabindex="-1">第二步：音素 → 字根 <a class="header-anchor" href="#第二步-音素-→-字根" aria-label="Permalink to &quot;第二步：音素 → 字根&quot;">​</a></h2><p>每个音素对应一个汉字部件，称为<strong>字根（wordroot）</strong>。</p><h3 id="声母字根" tabindex="-1">声母字根 <a class="header-anchor" href="#声母字根" aria-label="Permalink to &quot;声母字根&quot;">​</a></h3><table tabindex="0"><thead><tr><th>声母</th><th>字根</th><th>结构</th></tr></thead><tbody><tr><td>b</td><td>⿱不</td><td>上下</td></tr><tr><td>p</td><td>⿱攵</td><td>上下</td></tr><tr><td>m</td><td>⿰木</td><td>左右</td></tr><tr><td>f</td><td>⿱父</td><td>上下</td></tr><tr><td>d</td><td>⿱𠂊</td><td>上下</td></tr><tr><td>t</td><td>⿰七</td><td>左右</td></tr><tr><td>n</td><td>⿱冖</td><td>上下</td></tr><tr><td>l</td><td>⿺𠃊</td><td>左下包围</td></tr><tr><td>g</td><td>⿰𠂎</td><td>左右</td></tr><tr><td>k</td><td>⿰丬</td><td>左右</td></tr><tr><td>h</td><td>⿰丩</td><td>左右</td></tr><tr><td>j</td><td>⿱几</td><td>上下</td></tr><tr><td>q</td><td>⿱七</td><td>上下</td></tr><tr><td>x</td><td>⿱西</td><td>上下</td></tr><tr><td>zh</td><td>⿱止</td><td>上下</td></tr><tr><td>ch</td><td>⿱尺</td><td>上下</td></tr><tr><td>sh</td><td>⿸尸</td><td>左上包围</td></tr><tr><td>r</td><td>⿰日</td><td>左右</td></tr><tr><td>z</td><td>⿰子</td><td>左右</td></tr><tr><td>c</td><td>⿰朿</td><td>左右</td></tr><tr><td>s</td><td>⿱四</td><td>上下</td></tr></tbody></table><h3 id="韵母字根" tabindex="-1">韵母字根 <a class="header-anchor" href="#韵母字根" aria-label="Permalink to &quot;韵母字根&quot;">​</a></h3><table tabindex="0"><thead><tr><th>音素</th><th>字根</th><th>说明</th></tr></thead><tbody><tr><td>a</td><td>八</td><td></td></tr><tr><td>i</td><td>一</td><td></td></tr><tr><td>u</td><td>五</td><td></td></tr><tr><td>v (ü)</td><td>雨</td><td></td></tr><tr><td>ie</td><td>也</td><td>整体音素</td></tr><tr><td>ve (üe)</td><td>月</td><td>整体音素</td></tr><tr><td>ai</td><td>才</td><td></td></tr><tr><td>ei</td><td>巿</td><td></td></tr><tr><td>ao</td><td>刀</td><td></td></tr><tr><td>ou</td><td>口</td><td></td></tr><tr><td>ong</td><td>工</td><td></td></tr><tr><td>iong</td><td>用</td><td>整体音素（唯一零声母整体）</td></tr><tr><td>er</td><td>耳</td><td></td></tr><tr><td>en</td><td>⿵冂</td><td><strong>韵尾</strong>，上包围</td></tr><tr><td>an</td><td>⿵𰃦</td><td><strong>韵尾</strong>，上包围</td></tr><tr><td>eng</td><td>⿹𠃌</td><td><strong>韵尾</strong>，右上包围</td></tr><tr><td>ang</td><td>⿹勹</td><td><strong>韵尾</strong>，右上包围</td></tr></tbody></table><blockquote><p>韵尾（en、an、eng、ang）是特殊的——它们在组合时会<strong>包裹</strong>前一个字根，而不是简单拼接。</p></blockquote><h2 id="第三步-字根组合" tabindex="-1">第三步：字根组合 <a class="header-anchor" href="#第三步-字根组合" aria-label="Permalink to &quot;第三步：字根组合&quot;">​</a></h2><p>把字根用汉字结构指示符（IDC）组合起来，形成最终的音韵字。</p><p>组合规则详见<a href="/guide/combination-rules.html">组合规则详解</a>。</p><hr><p>继续阅读<a href="/guide/phoneme-to-root.html">音素 → 字根对照表</a>或直接进入<a href="/guide/playground.html">互动演示</a>。</p>`,28)])])}const u=d(n,[["render",r]]);export{g as __pageData,u as default};
